INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('able', 'qg', 1, 'QG', '有能力的；能够的；胜任的', 'having the power or skill to do something', 'She was able to lift the small box.', '她能够提起这个小箱子。', '[{"w":"acid","def":"acid: 相关性质或状态","vs":"与 able 相比，和主词同为描述性词，但强度或适用对象不同","use":"人物、物体、状态的细节描写，例如 \"acid\" / \"able\" 的替换练习"},{"w":"angry","def":"angry: 可比较的品质词","vs":"与 able 相比，比主词更强调外观、程度、功能或评价","use":"形容词辨析、对比句，例如 \"angry\" / \"able\" 的替换练习"}]'),
  ('acid', 'qg', 2, 'QG', '酸的；酸性的；尖刻的', 'having a sour taste or a chemical quality like acid', 'The acid fruit made his mouth tight.', '这种酸水果让他的嘴发紧。', '[{"w":"able","def":"able: 相关性质或状态","vs":"与 acid 相比，和主词同为描述性词，但强度或适用对象不同","use":"人物、物体、状态的细节描写，例如 \"able\" / \"acid\" 的替换练习"},{"w":"angry","def":"angry: 可比较的品质词","vs":"与 acid 相比，比主词更强调外观、程度、功能或评价","use":"形容词辨析、对比句，例如 \"angry\" / \"acid\" 的替换练习"},{"w":"automatic","def":"automatic: 同类描述词","vs":"与 acid 相比，意义接近但判断标准不同","use":"写作润色、口语评价，例如 \"automatic\" / \"acid\" 的替换练习"}]'),
